// frontend/src/components/BookCard.tsx
import React from 'react';
import { Book } from '../types';

interface BookCardProps {
  book: Book;
  actionButton?: React.ReactNode; 
}

const BookCard: React.FC<BookCardProps> = ({ book, actionButton }) => {
  return (
    <div className="group bg-white rounded-2xl border border-slate-100 p-4 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 flex flex-col h-full">
      {/* Görsel Alanı */}
      <div className="relative aspect-[2/3] w-full mb-4 overflow-hidden rounded-xl bg-slate-100">
        <img 
          src={book.coverImage || 'https://via.placeholder.com/150x200?text=No+Cover'} 
          alt={book.title} 
          className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
        />
        {/* Fiyat Etiketi (Görsel Üstünde) */}
        <div className="absolute top-2 right-2 bg-white/90 backdrop-blur-sm px-2 py-1 rounded-lg shadow-sm">
          <span className="text-sm font-black text-slate-800">₺{book.price}</span>
        </div>
      </div>

      {/* İçerik Alanı */}
      <div className="flex flex-col flex-grow text-center">
        <h3 className="text-lg font-bold text-slate-800 leading-tight mb-1 line-clamp-2 min-h-[3.5rem] flex items-center justify-center">
          {book.title}
        </h3>
        <p className="text-sm font-medium text-slate-500 mb-4 italic">
          {book.author}
        </p>

        {/* Alt Kısım ve Buton */}
        <div className="mt-auto">
          <div className="pt-4 border-t border-slate-50">
            {actionButton}
          </div>
        </div>
      </div>
    </div>
  );
};

export default BookCard;
